CSS = """
<style>
:root{--bg:#080d18;--panel:rgba(18,27,44,.78);--line:rgba(164,183,219,.16);--text:#edf4ff;--muted:#9aa8c1;--gold:#d8b86c;--cyan:#63d7ff;}
html,body,[data-testid="stAppViewContainer"]{background:radial-gradient(circle at top left,rgba(74,113,255,.19),transparent 34%),radial-gradient(circle at top right,rgba(216,184,108,.12),transparent 26%),linear-gradient(180deg,#080d18 0%,#0b1020 50%,#070a12 100%);color:var(--text)}
[data-testid="stHeader"]{background:rgba(8,13,24,0)}[data-testid="stToolbar"]{display:none}.block-container{padding-top:2rem;padding-bottom:4rem;max-width:1480px}
.hero{border:1px solid var(--line);background:linear-gradient(135deg,rgba(18,27,44,.92),rgba(9,15,28,.64));border-radius:30px;padding:32px 34px;box-shadow:0 24px 70px rgba(0,0,0,.33);position:relative;overflow:hidden}.hero:after{content:"";position:absolute;right:-120px;top:-120px;width:340px;height:340px;background:radial-gradient(circle,rgba(99,215,255,.16),transparent 64%);pointer-events:none}
.eyebrow{color:var(--gold);letter-spacing:.18em;text-transform:uppercase;font-size:.78rem;font-weight:800}.hero h1{font-size:3.15rem;line-height:1.02;margin:.35rem 0 .7rem 0;letter-spacing:-.055em}.hero p{color:var(--muted);font-size:1.04rem;max-width:860px;margin:0}.pill-row{display:flex;gap:10px;flex-wrap:wrap;margin-top:22px}.pill{border:1px solid rgba(216,184,108,.22);background:rgba(216,184,108,.08);color:#f5e7bc;padding:8px 12px;border-radius:999px;font-size:.82rem}
.power-panel{border:1px solid rgba(216,184,108,.22);background:rgba(216,184,108,.055);border-radius:24px;padding:20px;margin-top:18px}.metric-card{border:1px solid var(--line);background:linear-gradient(180deg,rgba(20,31,51,.82),rgba(12,19,33,.72));border-radius:22px;padding:21px;min-height:142px;box-shadow:0 16px 44px rgba(0,0,0,.23)}.metric-label{color:var(--muted);text-transform:uppercase;letter-spacing:.12em;font-size:.72rem;font-weight:800}.metric-value{color:#fff;font-size:2.28rem;font-weight:800;letter-spacing:-.04em;margin-top:8px}.metric-note{color:#aab6cc;font-size:.87rem;margin-top:7px;line-height:1.35}.section-title{margin-top:30px;margin-bottom:8px;font-size:1.25rem;font-weight:800;letter-spacing:-.02em}.section-subtitle{color:var(--muted);margin-bottom:16px;font-size:.93rem}.lane-card{border:1px solid var(--line);background:rgba(14,22,36,.62);border-radius:18px;padding:15px;min-height:112px}.lane-title{color:#fff;font-weight:800;font-size:.98rem}.lane-sub{color:var(--muted);font-size:.82rem;line-height:1.35;margin-top:5px}.signal{border-left:3px solid rgba(99,215,255,.85);background:rgba(99,215,255,.055);border-radius:14px;padding:12px 14px;margin-bottom:10px;color:#dceaff}.signal strong{color:#fff}.caption{color:var(--muted);font-size:.82rem}
div[data-testid="stButton"] button{width:100%;border-radius:16px;min-height:50px;border:1px solid rgba(216,184,108,.35);background:linear-gradient(135deg,rgba(216,184,108,.95),rgba(117,227,180,.7));color:#0a1020;font-weight:900}.stPlotlyChart{border-radius:22px;overflow:hidden}div[data-testid="stDataFrame"]{border:1px solid var(--line);border-radius:18px;overflow:hidden}
</style>
"""
